window.siteInspectorDb = {
    db: null,
    DB_NAME: 'SiteInspectorDb',
    DB_VERSION: 1,

    open: function () {
        return new Promise((resolve, reject) => {
            if (this.db) { resolve(); return; }
            const request = indexedDB.open(this.DB_NAME, this.DB_VERSION);
            request.onupgradeneeded = (e) => {
                const db = e.target.result;
                if (!db.objectStoreNames.contains('sites')) {
                    db.createObjectStore('sites', { keyPath: 'id' });
                }
                if (!db.objectStoreNames.contains('inspections')) {
                    const store = db.createObjectStore('inspections', { keyPath: 'id' });
                    store.createIndex('siteId', 'siteId', { unique: false });
                    store.createIndex('syncStatus', 'syncStatus', { unique: false });
                }
            };
            request.onsuccess = (e) => { this.db = e.target.result; resolve(); };
            request.onerror = (e) => reject(e.target.error);
        });
    },

    getAllSites: async function () {
        await this.open();
        return new Promise((resolve, reject) => {
            const tx = this.db.transaction('sites', 'readonly');
            const store = tx.objectStore('sites');
            const request = store.getAll();
            request.onsuccess = () => resolve(JSON.stringify(request.result || []));
            request.onerror = (e) => reject(e.target.error);
        });
    },

    saveSite: async function (json) {
        await this.open();
        return new Promise((resolve, reject) => {
            const tx = this.db.transaction('sites', 'readwrite');
            const store = tx.objectStore('sites');
            const site = JSON.parse(json);
            store.put(site);
            tx.oncomplete = () => resolve();
            tx.onerror = (e) => reject(e.target.error);
        });
    },

    deleteSite: async function (id) {
        await this.open();
        return new Promise((resolve, reject) => {
            const tx = this.db.transaction('sites', 'readwrite');
            const store = tx.objectStore('sites');
            store.delete(id);
            tx.oncomplete = () => resolve();
            tx.onerror = (e) => reject(e.target.error);
        });
    },

    getInspectionsForSite: async function (siteId) {
        await this.open();
        return new Promise((resolve, reject) => {
            const tx = this.db.transaction('inspections', 'readonly');
            const store = tx.objectStore('inspections');
            const index = store.index('siteId');
            const request = index.getAll(siteId);
            request.onsuccess = () => resolve(JSON.stringify(request.result || []));
            request.onerror = (e) => reject(e.target.error);
        });
    },

    getInspection: async function (id) {
        await this.open();
        return new Promise((resolve, reject) => {
            const tx = this.db.transaction('inspections', 'readonly');
            const store = tx.objectStore('inspections');
            const request = store.get(id);
            request.onsuccess = () => resolve(request.result ? JSON.stringify(request.result) : null);
            request.onerror = (e) => reject(e.target.error);
        });
    },

    saveInspection: async function (json) {
        await this.open();
        return new Promise((resolve, reject) => {
            const tx = this.db.transaction('inspections', 'readwrite');
            const store = tx.objectStore('inspections');
            const inspection = JSON.parse(json);
            store.put(inspection);
            tx.oncomplete = () => resolve();
            tx.onerror = (e) => reject(e.target.error);
        });
    },

    deleteInspection: async function (id) {
        await this.open();
        return new Promise((resolve, reject) => {
            const tx = this.db.transaction('inspections', 'readwrite');
            const store = tx.objectStore('inspections');
            store.delete(id);
            tx.oncomplete = () => resolve();
            tx.onerror = (e) => reject(e.target.error);
        });
    },

    getPendingInspections: async function () {
        await this.open();
        return new Promise((resolve, reject) => {
            const tx = this.db.transaction('inspections', 'readonly');
            const store = tx.objectStore('inspections');
            const request = store.getAll();
            request.onsuccess = () => {
                const pending = (request.result || []).filter(i => i.syncStatus !== 1);
                resolve(JSON.stringify(pending));
            };
            request.onerror = (e) => reject(e.target.error);
        });
    },

    getAllInspections: async function () {
        await this.open();
        return new Promise((resolve, reject) => {
            const tx = this.db.transaction('inspections', 'readonly');
            const store = tx.objectStore('inspections');
            const request = store.getAll();
            request.onsuccess = () => resolve(JSON.stringify(request.result || []));
            request.onerror = (e) => reject(e.target.error);
        });
    },

    getInspectionCountForSite: async function (siteId) {
        await this.open();
        return new Promise((resolve, reject) => {
            const tx = this.db.transaction('inspections', 'readonly');
            const store = tx.objectStore('inspections');
            const index = store.index('siteId');
            const request = index.count(siteId);
            request.onsuccess = () => resolve(request.result);
            request.onerror = (e) => reject(e.target.error);
        });
    }
};

window.connectivityHelper = {
    isOnline: function () {
        return navigator.onLine;
    },

    registerOnlineHandler: function (dotNetRef) {
        window.addEventListener('online', () => {
            dotNetRef.invokeMethodAsync('OnConnectivityChanged', true);
        });
        window.addEventListener('offline', () => {
            dotNetRef.invokeMethodAsync('OnConnectivityChanged', false);
        });
    }
};

window.photoHelper = {
    resizeImage: function (dataUrl, maxWidth) {
        return new Promise((resolve) => {
            const img = new Image();
            img.onload = () => {
                let width = img.width;
                let height = img.height;
                if (width > maxWidth) {
                    height = Math.round((height * maxWidth) / width);
                    width = maxWidth;
                }
                const canvas = document.createElement('canvas');
                canvas.width = width;
                canvas.height = height;
                const ctx = canvas.getContext('2d');
                ctx.drawImage(img, 0, 0, width, height);
                resolve(canvas.toDataURL('image/jpeg', 0.8));
            };
            img.src = dataUrl;
        });
    },

    readFileAsDataUrl: function (inputId) {
        return new Promise((resolve, reject) => {
            const input = document.getElementById(inputId);
            if (!input || !input.files || input.files.length === 0) {
                resolve(null);
                return;
            }
            const file = input.files[0];
            const reader = new FileReader();
            reader.onload = (e) => resolve(e.target.result);
            reader.onerror = (e) => reject(e);
            reader.readAsDataURL(file);
        });
    }
};

window.localStorageHelper = {
    get: function (key) {
        return localStorage.getItem(key);
    },
    set: function (key, value) {
        localStorage.setItem(key, value);
    }
};

using System.Text.Json;
using System.Text.Json.Serialization;
using Microsoft.JSInterop;
using SiteInspector.Models;

namespace SiteInspector.Services;

public class IndexedDbService
{
    private readonly IJSRuntime _js;
    private static readonly JsonSerializerOptions JsonOptions = new()
    {
        PropertyNamingPolicy = JsonNamingPolicy.CamelCase,
        Converters = { new JsonStringEnumConverter() }
    };

    public IndexedDbService(IJSRuntime js) => _js = js;

    public async Task<List<InspectionSite>> GetAllSitesAsync()
    {
        var json = await _js.InvokeAsync<string>("siteInspectorDb.getAllSites");
        return JsonSerializer.Deserialize<List<InspectionSite>>(json, JsonOptions) ?? new();
    }

    public async Task SaveSiteAsync(InspectionSite site)
    {
        var json = JsonSerializer.Serialize(site, JsonOptions);
        await _js.InvokeVoidAsync("siteInspectorDb.saveSite", json);
    }

    public async Task DeleteSiteAsync(string id)
    {
        await _js.InvokeVoidAsync("siteInspectorDb.deleteSite", id);
    }

    public async Task<List<Inspection>> GetInspectionsForSiteAsync(string siteId)
    {
        var json = await _js.InvokeAsync<string>("siteInspectorDb.getInspectionsForSite", siteId);
        return JsonSerializer.Deserialize<List<Inspection>>(json, JsonOptions) ?? new();
    }

    public async Task<Inspection?> GetInspectionAsync(string id)
    {
        var json = await _js.InvokeAsync<string?>("siteInspectorDb.getInspection", id);
        return json is null ? null : JsonSerializer.Deserialize<Inspection>(json, JsonOptions);
    }

    public async Task SaveInspectionAsync(Inspection inspection)
    {
        var json = JsonSerializer.Serialize(inspection, JsonOptions);
        await _js.InvokeVoidAsync("siteInspectorDb.saveInspection", json);
    }

    public async Task DeleteInspectionAsync(string id)
    {
        await _js.InvokeVoidAsync("siteInspectorDb.deleteInspection", id);
    }

    public async Task<List<Inspection>> GetPendingInspectionsAsync()
    {
        var json = await _js.InvokeAsync<string>("siteInspectorDb.getPendingInspections");
        return JsonSerializer.Deserialize<List<Inspection>>(json, JsonOptions) ?? new();
    }

    public async Task<List<Inspection>> GetAllInspectionsAsync()
    {
        var json = await _js.InvokeAsync<string>("siteInspectorDb.getAllInspections");
        return JsonSerializer.Deserialize<List<Inspection>>(json, JsonOptions) ?? new();
    }

    public async Task<int> GetInspectionCountForSiteAsync(string siteId)
    {
        return await _js.InvokeAsync<int>("siteInspectorDb.getInspectionCountForSite", siteId);
    }
}

