+            reader.onload = (e) => resolve(e.target.result);
+            reader.onerror = (e) => reject(e);
+            reader.readAsDataURL(file);
+        });
+    }
+};
+
+window.localStorageHelper = {
+    get: function (key) {
+        return localStorage.getItem(key);
+    },
+    set: function (key, value) {
+        localStorage.setItem(key, value);
+    }
+};
