+using System.Net.Http.Json;
+using SiteInspector.Models;
+
+namespace SiteInspector.Services;
+
+public class SyncService : IDisposable
+{
+    private readonly IndexedDbService _db;
+    private readonly ConnectivityService _connectivity;
+    private readonly HttpClient _http;
+    private Timer? _timer;
+    private bool _isSyncing;
+
+    public string ApiEndpoint { get; set; } = "https://api.example.com/inspections";
+    public int PendingCount { get; private set; }
+    public bool IsOnline => _connectivity.IsOnline;
+    public event Action? OnSyncStateChanged;
+
+    public SyncService(IndexedDbService db, ConnectivityService connectivity, HttpClient http)
+    {
+        _db = db;
+        _connectivity = connectivity;
+        _http = http;
+    }
+
+    public async Task StartAsync()
+    {
+        await _connectivity.InitializeAsync();
+        _connectivity.OnConnectivityChanged += async (online) =>
+        {
+            OnSyncStateChanged?.Invoke();
+            if (online) await SyncPendingAsync();
+        };
+        await UpdatePendingCountAsync();
+        _timer = new Timer(async _ => await SyncPendingAsync(), null, TimeSpan.FromSeconds(5), TimeSpan.FromSeconds(30));
+    }
+
+    public async Task SyncPendingAsync()
+    {
+        if (_isSyncing || !_connectivity.IsOnline) return;
+        _isSyncing = true;
+        try
+        {
+            var pending = await _db.GetPendingInspectionsAsync();
+            foreach (var inspection in pending)
+            {
+                try
+                {
+                    var response = await _http.PostAsJsonAsync(ApiEndpoint, inspection);
+                    if (response.IsSuccessStatusCode)
+                    {
+                        inspection.SyncStatus = SyncStatus.Synced;
+                        inspection.LastSyncedAt = DateTime.UtcNow;
+                        await _db.SaveInspectionAsync(inspection);
+                    }
+                    else
+                    {
+                        inspection.SyncStatus = SyncStatus.Error;
+                        await _db.SaveInspectionAsync(inspection);
+                    }
+                }
+                catch
+                {
+                    inspection.SyncStatus = SyncStatus.Pending;
+                }
+            }
+            await UpdatePendingCountAsync();
+            OnSyncStateChanged?.Invoke();
+        }
+        finally
+        {
+            _isSyncing = false;
+        }
+    }
+
+    public async Task UpdatePendingCountAsync()
+    {
+        try
+        {
+            var pending = await _db.GetPendingInspectionsAsync();
+            PendingCount = pending.Count;
+        }
+        catch
+        {
+            PendingCount = 0;
+        }
+    }
+
+    public void Dispose()
+    {
+        _timer?.Dispose();
+    }
+}
