<div class="page-header">
    <button class="btn-back" @onclick="GoBack">← Back</button>
    <h1>Inspection</h1>
</div>

@if (inspection is null)
{
    <p class="loading">Loading...</p>
}
else
{
    <div class="form-container">
        <div class="form-group">
            <label>Site</label>
            <div class="form-static">@inspection.SiteName</div>
        </div>

        <div class="form-group">
            <label for="inspectorName">Inspector Name</label>
            <input id="inspectorName" type="text" @bind="inspection.InspectorName"
                   @bind:after="AutoSave" placeholder="Your name" />
        </div>

        <div class="form-group">
            <label for="notes">General Notes</label>
            <textarea id="notes" @bind="inspection.Notes" @bind:after="AutoSave"
                      placeholder="Overall inspection notes..." rows="3"></textarea>
        </div>

        <!-- Checklist Section -->
        <h2 class="section-title">Safety Checklist</h2>

        @foreach (var category in inspection.ChecklistItems.GroupBy(c => c.Category))
        {
            <div class="checklist-category">
                <h3 class="category-title">@category.Key</h3>
                @foreach (var item in category)
                {
                    <div class="checklist-item">
                        <div class="checklist-description">@item.Description</div>
                        <div class="checklist-buttons">
                            <button class="check-btn pass @(item.Result == CheckResult.Pass ? "active" : "")"
                                    @onclick="() => SetResult(item, CheckResult.Pass)">✓ Pass</button>
                            <button class="check-btn fail @(item.Result == CheckResult.Fail ? "active" : "")"
                                    @onclick="() => SetResult(item, CheckResult.Fail)">✗ Fail</button>
                            <button class="check-btn na @(item.Result == CheckResult.NotApplicable ? "active" : "")"
                                    @onclick="() => SetResult(item, CheckResult.NotApplicable)">N/A</button>
                        </div>
                        <div class="checklist-notes-toggle" @onclick="() => ToggleNotes(item.Id)">
                            @(expandedNotes.Contains(item.Id) ? "▼ Hide notes" : "▶ Add notes")
                        </div>
                        @if (expandedNotes.Contains(item.Id))
                        {
                            <input type="text" class="checklist-note-input" @bind="item.Notes"
                                   @bind:after="AutoSave" placeholder="Notes for this item..." />
                        }
                    </div>
                }
            </div>
        }

        <!-- Photo Section -->
        <h2 class="section-title">Photos</h2>

        <div class="photo-upload">
            <label for="photoInput" class="btn-secondary">📷 Add Photo</label>
            <input id="photoInput" type="file" accept="image/*" capture="environment"
                   @onchange="OnPhotoSelected" style="display:none" />
        </div>

        @if (inspection.Photos.Count > 0)
        {
            <div class="photo-grid">
                @foreach (var photo in inspection.Photos)
                {
                    <div class="photo-card">
                        <img src="@photo.DataUrl" alt="@photo.Caption" class="photo-thumb" />
                        <input type="text" @bind="photo.Caption" @bind:after="AutoSave"
                               placeholder="Caption..." class="photo-caption-input" />
                        <button class="btn-danger-small" @onclick="() => RemovePhoto(photo)">Remove</button>
                    </div>
                }
            </div>
        }
    </div>

    <div class="bottom-actions">
        <button class="btn-secondary full-width" @onclick="SaveDraft">Save Draft</button>
        <button class="btn-primary full-width" @onclick="Submit">Submit Inspection</button>
    </div>
}

@code {
    [Parameter] public string InspectionId { get; set; } = "";

    private Inspection? inspection;
    private HashSet<string> expandedNotes = new();

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            inspection = await Db.GetInspectionAsync(InspectionId);
            if (inspection is not null)
            {
                var savedName = await JS.InvokeAsync<string?>("localStorageHelper.get", "inspectorName");
                if (string.IsNullOrWhiteSpace(inspection.InspectorName) && !string.IsNullOrWhiteSpace(savedName))
                {
                    inspection.InspectorName = savedName;
                }
            }
            StateHasChanged();
        }
    }

    private async Task SetResult(ChecklistItem item, CheckResult result)
    {
        item.Result = result;
        await AutoSave();
    }

    private void ToggleNotes(string itemId)
    {
        if (!expandedNotes.Remove(itemId))
            expandedNotes.Add(itemId);
    }

    private async Task OnPhotoSelected()
    {
        if (inspection is null) return;
        try
        {
            var dataUrl = await JS.InvokeAsync<string?>("photoHelper.readFileAsDataUrl", "photoInput");
            if (string.IsNullOrEmpty(dataUrl)) return;

            var resized = await JS.InvokeAsync<string>("photoHelper.resizeImage", dataUrl, 1920);

            var photo = new InspectionPhoto
            {
                FileName = $"photo_{DateTime.UtcNow:yyyyMMdd_HHmmss}.jpg",
                DataUrl = resized
            };
            inspection.Photos.Add(photo);
            await AutoSave();
        }
        catch { /* Ignore photo errors gracefully */ }
    }

    private async Task RemovePhoto(InspectionPhoto photo)
    {
        if (inspection is null) return;
        inspection.Photos.Remove(photo);
        await AutoSave();
    }

    private async Task AutoSave()
    {
        if (inspection is null) return;
        if (!string.IsNullOrWhiteSpace(inspection.InspectorName))
        {
            await JS.InvokeVoidAsync("localStorageHelper.set", "inspectorName", inspection.InspectorName);
        }
        await Db.SaveInspectionAsync(inspection);
    }

    private async Task SaveDraft()
    {
        if (inspection is null) return;
        inspection.Status = InspectionStatus.Draft;
        await AutoSave();
        Nav.NavigateTo($"/site/{inspection.SiteId}");
    }

    private async Task Submit()
    {
        if (inspection is null) return;
        inspection.Status = InspectionStatus.Submitted;
        inspection.SyncStatus = SyncStatus.Pending;
        await AutoSave();
        await Sync.UpdatePendingCountAsync();
        Nav.NavigateTo($"/site/{inspection.SiteId}");
    }

    private void GoBack()
    {
        if (inspection is not null)
            Nav.NavigateTo($"/site/{inspection.SiteId}");
        else
            Nav.NavigateTo("/");
    }
}

