@page "/"
@using SiteInspector.Models
@using SiteInspector.Services
@inject IndexedDbService Db
@inject SyncService Sync
@inject NavigationManager Nav
@implements IDisposable

<div class="page-header">
    <h1>Construction Sites</h1>
    <button class="btn-primary" @onclick="GoToAddSite">+ Add Site</button>
</div>

<div class="sync-bar">
    <span class="connectivity-badge @(Sync.IsOnline ? "online" : "offline")">
        @(Sync.IsOnline ? "Online" : "Offline")
    </span>
    @if (Sync.PendingCount > 0)
    {
        <span class="pending-badge">@Sync.PendingCount pending sync</span>
    }
</div>

@if (sites is null)
{
    <p class="loading">Loading sites...</p>
}
else if (sites.Count == 0)
{
    <div class="empty-state">
        <p>No construction sites yet.</p>
        <p>Tap <strong>+ Add Site</strong> to get started.</p>
    </div>
}
else
{
    <div class="card-list">
        @foreach (var site in sites.OrderByDescending(s => s.CreatedAt))
        {
            <div class="card" @onclick="() => GoToSite(site.Id)">
                <div class="card-title">@site.Name</div>
                <div class="card-subtitle">@site.Address</div>
                <div class="card-meta">
                    @if (inspectionCounts.ContainsKey(site.Id))
                    {
                        <span>@inspectionCounts[site.Id] inspection(s)</span>
                    }
                    <span class="card-date">@site.CreatedAt.ToLocalTime().ToString("MMM dd, yyyy")</span>
                </div>
            </div>
        }
    </div>
}

@code {
    private List<InspectionSite>? sites;
    private Dictionary<string, int> inspectionCounts = new();

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            await LoadData();
            Sync.OnSyncStateChanged += OnSyncChanged;
            StateHasChanged();
        }
    }

    private async void OnSyncChanged()
    {
        await InvokeAsync(StateHasChanged);
    }

    private async Task LoadData()
    {
        sites = await Db.GetAllSitesAsync();
        inspectionCounts.Clear();
        foreach (var site in sites)
        {
            inspectionCounts[site.Id] = await Db.GetInspectionCountForSiteAsync(site.Id);
        }
    }

    private void GoToAddSite() => Nav.NavigateTo("/add-site");
    private void GoToSite(string id) => Nav.NavigateTo($"/site/{id}");

    public void Dispose()
    {
        Sync.OnSyncStateChanged -= OnSyncChanged;
    }
}

