+                </div>
+            </div>
+        }
+    </div>
+}
+
+@code {
+    private List<InspectionSite>? sites;
+    private Dictionary<string, int> inspectionCounts = new();
+
+    protected override async Task OnAfterRenderAsync(bool firstRender)
+    {
+        if (firstRender)
+        {
+            await LoadData();
+            Sync.OnSyncStateChanged += OnSyncChanged;
+            StateHasChanged();
+        }
+    }
+
+    private async void OnSyncChanged()
+    {
+        await InvokeAsync(StateHasChanged);
+    }
+
+    private async Task LoadData()
+    {
+        sites = await Db.GetAllSitesAsync();
+        inspectionCounts.Clear();
+        foreach (var site in sites)
+        {
+            inspectionCounts[site.Id] = await Db.GetInspectionCountForSiteAsync(site.Id);
+        }
+    }
+
+    private void GoToAddSite() => Nav.NavigateTo("/add-site");
+    private void GoToSite(string id) => Nav.NavigateTo($"/site/{id}");
+
+    public void Dispose()
+    {
+        Sync.OnSyncStateChanged -= OnSyncChanged;
+    }
+}

