.card:active { box-shadow: 0 1px 8px rgba(0,0,0,0.15); }
.card-title { font-size: 1.05rem; font-weight: 600; margin-bottom: 4px; }
.card-subtitle { font-size: 0.9rem; color: #64748b; margin-bottom: 8px; }
.card-meta { display: flex; justify-content: space-between; font-size: 0.8rem; color: #94a3b8; }

/* Status badges */
.status-badge, .sync-badge {
    padding: 2px 10px; border-radius: 12px; font-size: 0.75rem; font-weight: 600; text-transform: uppercase;
