.status-draft { background: #fef3c7; color: #92400e; }
.status-submitted { background: #d1fae5; color: #065f46; }
.sync-pending { background: #fef3c7; color: #92400e; }
.sync-synced { background: #d1fae5; color: #065f46; }
.sync-error { background: #fee2e2; color: #991b1b; }

/* Forms */
.form-container { display: flex; flex-direction: column; gap: 16px; }
.form-group { display: flex; flex-direction: column; gap: 4px; }
.form-group label { font-size: 0.85rem; font-weight: 600; color: #475569; }
.form-group input, .form-group textarea {
    width: 100%; padding: 12px; border: 1.5px solid #cbd5e1; border-radius: 8px;
